"use strict";async function inject(t,e){const n=document.getElementById(t);if(!n)return;const a=await fetch(e);a.ok?n.outerHTML=await a.text():console.error(`layout.js: failed to load ${e}`)}function hidePennylaneRedundantFooterLogos(){"pennylane"===sessionStorage.getItem("quiz_connexion")&&document.querySelectorAll('[data-partner-logo="tiime"], [data-partner-logo="indy"]').forEach(t=>{t.hidden=!0})}document.addEventListener("DOMContentLoaded",()=>{inject("site-header","partials/header.html"),inject("site-footer","partials/footer.html").then(hidePennylaneRedundantFooterLogos),inject("partner-banner","partials/partner-banner.html")});